const cellKey = (x: number, y: number): string => `${x},${y}`;

const isLiveAt = (liveSet: ReadonlySet<string>, x: number, y: number): boolean =>
  liveSet.has(cellKey(x, y));

const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

const countLiveNeighbors = (cell: Cell, liveSet: ReadonlySet<string>): number =>
  neighborsOf(cell).filter(([nx, ny]) => isLiveAt(liveSet, nx, ny)).length;

const willBeAlive = (cell: Cell, liveSet: ReadonlySet<string>): boolean => {
  const count = countLiveNeighbors(cell, liveSet);
  return isLiveAt(liveSet, cell[0], cell[1])
    ? count === 2 || count === 3
    : count === 3;
};

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));

  const candidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    candidates.set(cellKey(cell[0], cell[1]), cell);
    for (const neighbor of neighborsOf(cell)) {
      candidates.set(cellKey(neighbor[0], neighbor[1]), neighbor);
    }
  }

  return [...candidates.values()].filter((cell) => willBeAlive(cell, liveSet));
}

